arguments.argument:
if global.gamePaused=false
{
  if atkProg=0
  {
    image_angle+=8
    atkTime+=1
    if atkTime>=atkDelay
    {
      if type=0
      {
        image_angle=point_direction(x,y,oPlayer1.x,oPlayer1.y-32)
      }
      else if type=1
      {
        image_angle=myDir
      }
      direction=image_angle
      image_blend=c_white
      bCanDealDamage=true
      atkTime=0; atkProg=1
    }
  }
  else if atkProg=1
  {
    atkTime+=1
    if atkTime>=15 {atkTime=0; atkProg=2}
  }
  else if atkProg=2
  {
    if bulletSpeed<2 {bulletSpeed+=0.1}
    else if bulletSpeed>=2 and bulletSpeed<=15 {bulletSpeed+=1}
    speed=bulletSpeed
  }
}
else {speed=0}
